func abs(x int64) int64 {
    if x < 0 {
        return -x
    }
    return x
}

func gcd(a, b int64) int64 {
    a = abs(a)
    b = abs(b)
    for b != 0 {
        a, b = b, a % b
    }
    return a
}

type Slope struct {
    dx int64
    dy int64
}

func normalize(dx, dy int64) Slope {
    if dx == 0 && dy == 0 {
        return Slope{0, 0}
    }
    if dx == 0 {
        return Slope{0, 1}
    }
    if dy == 0 {
        return Slope{1, 0}
    }
    g := gcd(dx, dy)
    dx /= g
    dy /= g
    if dx < 0 {
        dx = -dx
        dy = -dy
    }
    return Slope{dx, dy}
}

func solve(points [][]int64) int64 {
    n := len(points)
    slopeMap := make(map[Slope][][2]int)

    for i := 0; i < n; i++ {
        for j := i+1; j < n; j++ {
            x1, y1 := points[i][0], points[i][1]
            x2, y2 := points[j][0], points[j][1]
            dx := x2 - x1
            dy := y2 - y1
            s := normalize(dx, dy)
            slopeMap[s] = append(slopeMap[s], [2]int{i, j})
        }
    }

    totalC := int64(0)
    for _, segs := range slopeMap {
        m := int64(len(segs))
        total_pairs := m * (m-1) / 2

        deg := make([]int64, n)
        for _, seg := range segs {
            u, v := seg[0], seg[1]
            deg[u]++
            deg[v]++
        }

        non_disjoint := int64(0)
        for i := 0; i < n; i++ {
            if deg[i] >= 2 {
                non_disjoint += deg[i] * (deg[i]-1) / 2
            }
        }

        disjoint_pairs := total_pairs - non_disjoint
        totalC += disjoint_pairs
    }

    midMap := make(map[[2]int64]int64)
    for i := 0; i < n; i++ {
        for j := i+1; j < n; j++ {
            x1, y1 := points[i][0], points[i][1]
            x2, y2 := points[j][0], points[j][1]
            key := [2]int64{x1 + x2, y1 + y2}
            midMap[key]++
        }
    }

    totalPara := int64(0)
    for _, cnt := range midMap {
        totalPara += cnt * (cnt-1) / 2
    }

    return totalC - totalPara
}
