func solve(points [][]int64) int64 {
	n := len(points)
	if n < 4 {
		return 0
	}

	abs := func(x int64) int64 {
		if x < 0 {
			return -x
		}
		return x
	}

	gcd := func(a, b int64) int64 {
		for b != 0 {
			a, b = b, a%b
		}
		return a
	}

	groups := make(map[[2]int64]map[int]int)

	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			a := points[i]
			b := points[j]
			dx := b[0] - a[0]
			dy := b[1] - a[1]

			if dx == 0 && dy == 0 {
				continue
			}

			var key [2]int64
			if dx == 0 {
				key = [2]int64{0, 1}
			} else {
				if dx < 0 {
					dx = -dx
					dy = -dy
				}
				g := gcd(dx, abs(dy))
				if g != 0 {
					dx /= g
					dy /= g
				}
				key = [2]int64{dx, dy}
			}

			if groups[key] == nil {
				groups[key] = make(map[int]int)
			}
			groups[key][i]++
			groups[key][j]++
		}
	}

	total_slope_count := int64(0)
	for _, degMap := range groups {
		total_edges := int64(0)
		for _, deg := range degMap {
			total_edges += int64(deg)
		}
		total_edges /= 2
		if total_edges < 2 {
			continue
		}
		disjoint_pairs := total_edges * (total_edges - 1) / 2
		for _, deg := range degMap {
			if deg >= 2 {
				disjoint_pairs -= int64(deg) * int64(deg-1) / 2
			}
		}
		total_slope_count += disjoint_pairs
	}

	midPointCounts := make(map[[2]int64]int)
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			sx := points[i][0] + points[j][0]
			sy := points[i][1] + points[j][1]
			key := [2]int64{sx, sy}
			midPointCounts[key]++
		}
	}

	parallelograms := int64(0)
	for _, count := range midPointCounts {
		if count > 1 {
			parallelograms += int64(count) * int64(count-1) / 2
		}
	}

	return total_slope_count - parallelograms
}
