import (
	"sort"
)

type Point []int64

func cross(a, b, c Point) int64 {
	return (b[0]-a[0])*(c[1]-a[1]) - (c[0]-a[0])*(b[1]-a[1])
}

func convexHull4(points []Point) []Point {
	n := len(points)
	if n <= 3 {
		return points
	}
	sorted := make([]Point, n)
	copy(sorted, points)
	sort.Slice(sorted, func(i, j int) bool {
		if sorted[i][0] == sorted[j][0] {
			return sorted[i][1] < sorted[j][1]
		}
		return sorted[i][0] < sorted[j][0]
	})

	lower := []Point{}
	for i := 0; i < n; i++ {
		for len(lower) >= 2 {
			last := lower[len(lower)-1]
			secondLast := lower[len(lower)-2]
			c := sorted[i]
			if cross(secondLast, last, c) <= 0 {
				lower = lower[:len(lower)-1]
			} else {
				break
			}
		}
		lower = append(lower, sorted[i])
	}

	upper := []Point{}
	for i := n - 1; i >= 0; i-- {
		for len(upper) >= 2 {
			last := upper[len(upper)-1]
			secondLast := upper[len(upper)-2]
			c := sorted[i]
			if cross(secondLast, last, c) <= 0 {
				upper = upper[:len(upper)-1]
			} else {
				break
			}
		}
		upper = append(upper, sorted[i])
	}

	allPoints := make([]Point, 0)
	if len(lower) > 0 {
		lower = lower[:len(lower)-1]
	}
	for i := 0; i < len(lower); i++ {
		allPoints = append(allPoints, lower[i])
	}
	if len(upper) > 0 {
		upper = upper[:len(upper)-1]
	}
	for i := 0; i < len(upper); i++ {
		allPoints = append(allPoints, upper[i])
	}
	return allPoints
}

func solve(points [][]int64) int64 {
	n := len(points)
	var count int64 = 0
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			for k := j + 1; k < n; k++ {
				for l := k + 1; l < n; l++ {
					fourPoints := []Point{
						points[i],
						points[j],
						points[k],
						points[l],
					}
					hull := convexHull4(fourPoints)
					if len(hull) != 4 {
						continue
					}

					side1a, side1b := hull[0], hull[1]
					side2a, side2b := hull[1], hull[2]
					side3a, side3b := hull[2], hull[3]
					side4a, side4b := hull[3], hull[0]

					if parallel(side1a, side1b, side3a, side3b) {
						count++
						continue
					}
					if parallel(side2a, side2b, side4a, side4b) {
						count++
						continue
					}
				}
			}
		}
	}
	return count
}

func parallel(a, b, c, d Point) bool {
	dx1 := b[0] - a[0]
	dy1 := b[1] - a[1]
	dx2 := d[0] - c[0]
	dy2 := d[1] - c[1]
	return dx1*dy2 == dx2*dy1
}
```

